def fibonacci(n):
    """
    Tính số Fibonacci thứ n bằng phương pháp đệ quy.
    """
    if n <= 0:
        return 0
    elif n == 1:
        return 1
    else:
        return fibonacci(n - 1) + fibonacci(n - 2)

